class Solution {
    public List<Integer> beautifulIndices(String s, String a, String b, int k) {
        List<Integer> res = new ArrayList<>();
        int[] aIndices = findIndices(s, a);
        int[] bIndices = findIndices(s, b);
        for (int i : aIndices) {
            if (checkWithinK(i, bIndices, k)) {
                res.add(i);
            }
        }
        return res;
    }

    private int[] findIndices(String s, String target) {
        List<Integer> indices = new ArrayList<>();
        for (int i = 0; i <= s.length() - target.length(); i++) {
            if (s.substring(i, i + target.length()).equals(target)) {
                indices.add(i);
            }
        }
        int[] arr = new int[indices.size()];
        for (int i = 0; i < indices.size(); i++) {
            arr[i] = indices.get(i);
        }
        return arr;
    }

    private boolean checkWithinK(int aIndex, int[] bIndices, int k) {
        int left = 0, right = bIndices.length - 1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (Math.abs(aIndex - bIndices[mid]) <= k) {
                return true;
            } else if (aIndex - bIndices[mid] < 0) {
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }
        return false;
    }
}
